    """HTML-formatted message, grouped by track, for the Telegram bot."""
    esc = html.escape

    # Group rows by track, preserving first-seen order.
    groups: dict[str, list[dict]] = {}
    for r in rows:
        groups.setdefault(r["track"], []).append(r)

    parts = [f"🏆 <b>AI-for-Vietnam Problem Statements</b>\n📊 <b>{len(rows)}</b> total"]
    for track, items in groups.items():
        emoji, label = TRACK_LABELS.get(track, ("📌", track))
        parts.append(f"\n{emoji} <b>{esc(label)}</b> ({len(items)})\n➖➖➖➖➖➖➖➖➖➖")
